const NR_ENV = env.get('NODE_RED_ENV') || 'prod';
if (NR_ENV !== 'prod') {
    msg.cfIdentity = { email: 'dev-bypass@local', dev: true };
    return [msg, null];
}

const CF_TEAM_DOMAIN = env.get('CF_ACCESS_TEAM_DOMAIN') || 'uniumautomacao.cloudflareaccess.com';
const CF_AUD = env.get('CF_ACCESS_AUD');

if (!CF_AUD) {
    msg.statusCode = 500;
    msg.payload = { error: 'CF_ACCESS_AUD not configured' };
    return [null, msg];
}

const jwt = msg.req && msg.req.headers && msg.req.headers['cf-access-jwt-assertion'];
if (!jwt) {
    msg.statusCode = 401;
    msg.payload = { error: 'Missing CF Access JWT' };
    return [null, msg];
}

try {
    const parts = jwt.split('.');
    if (parts.length !== 3) throw new Error('Invalid JWT format');

    const header = JSON.parse(Buffer.from(parts[0], 'base64url').toString());
    if (header.alg !== 'RS256') throw new Error('Unexpected JWT algorithm: ' + header.alg);
    const payload = JSON.parse(Buffer.from(parts[1], 'base64url').toString());

    if (!payload.exp || payload.exp < Math.floor(Date.now() / 1000)) {
        throw new Error('Token expired');
    }
    if (!payload.aud || (Array.isArray(payload.aud) ? !payload.aud.includes(CF_AUD) : payload.aud !== CF_AUD)) {
        throw new Error('Invalid audience');
    }
    const expectedIssuer = 'https://' + CF_TEAM_DOMAIN;
    if (payload.iss !== expectedIssuer) {
        throw new Error('Invalid issuer: ' + payload.iss);
    }

    const cacheKey = '_cf_jwks_orcamentos';
    let jwks = flow.get(cacheKey);
    const now = Date.now();
    if (!jwks || !jwks.keys || !jwks.fetchedAt || (now - jwks.fetchedAt > 3600000)) {
        const jwksUrl = 'https://' + CF_TEAM_DOMAIN + '/cdn-cgi/access/certs';
        const jwksData = await new Promise((resolve, reject) => {
            const urlObj = new URL(jwksUrl);
            const req = httpsLib.request({ hostname: urlObj.hostname, path: urlObj.pathname, method: 'GET' }, (r) => {
                let data = '';
                r.on('data', c => data += c);
                r.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { reject(new Error('JWKS parse error')); } });
            });
            req.setTimeout(10000, () => { req.destroy(new Error('JWKS fetch timeout')); });
            req.on('error', reject);
            req.end();
        });
        jwks = { keys: jwksData.keys, fetchedAt: now };
        flow.set(cacheKey, jwks);
    }

    const kid = header.kid;
    const jwk = jwks.keys.find(k => k.kid === kid);
    if (!jwk) throw new Error('No matching JWK for kid: ' + kid);

    const pubKey = cryptoLib.createPublicKey({ key: jwk, format: 'jwk' });
    const signatureInput = parts[0] + '.' + parts[1];
    const signature = Buffer.from(parts[2], 'base64url');
    const isValid = cryptoLib.verify('RSA-SHA256', Buffer.from(signatureInput), pubKey, signature);

    if (!isValid) throw new Error('Invalid JWT signature');

    msg.cfIdentity = payload;
    return [msg, null];
} catch (err) {
    node.warn('[CF Access - Orcamentos] Validation failed: ' + err.message);
    msg.statusCode = 401;
    msg.payload = { error: 'Unauthorized' };
    return [null, msg];
}

const pgReq = global.get('pgReq');
if (typeof pgReq !== 'function') {
    node.error('[authz] pgReq helper not available');
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'pgReq_not_available' };
    return [null, msg];
}

// 1. Require cfIdentity upstream
const email = msg.cfIdentity && msg.cfIdentity.email;
if (!email) {
    msg.statusCode = 401;
    msg.payload = { ok: false, error: 'missing_identity' };
    return [null, msg];
}

// 2. Profile lookup for AUDIT ONLY (non-blocking — DEV bypass emails may not match)
try {
    const pres = await pgReq('GET', '/profiles?email=eq.' + encodeURIComponent(email) + '&select=id');
    if (pres && pres.statusCode === 200 && Array.isArray(pres.body) && pres.body.length > 0) {
        msg.audit_profile_id = pres.body[0].id;
    }
} catch (e) {
    node.warn('[authz] profile lookup failed (non-blocking): ' + (e && e.message ? e.message : String(e)));
}

// 3. Data-integrity check: if BOTH creditoId and orcamentoId are provided, they must
//    belong to the same cliente. Single-resource flows skip the cross-check.
const p = msg.payload || {};
const creditoId = p.creditoId || p.creditoid || msg.creditoId;
const orcamentoId = p.orcamentoId || p.orcamentoid || msg.orcamentoId;

try {
    if (creditoId && orcamentoId) {
        const [cRes, oRes] = await Promise.all([
            pgReq('GET', '/creditos_do_cliente?id=eq.' + encodeURIComponent(creditoId) + '&select=cliente_id'),
            pgReq('GET', '/orcamentos?id=eq.' + encodeURIComponent(orcamentoId) + '&select=cliente_id')
        ]);
        if (cRes.statusCode !== 200 || !Array.isArray(cRes.body) || cRes.body.length === 0) {
            msg.statusCode = 404;
            msg.payload = { ok: false, error: 'credito_not_found' };
            return [null, msg];
        }
        if (oRes.statusCode !== 200 || !Array.isArray(oRes.body) || oRes.body.length === 0) {
            msg.statusCode = 404;
            msg.payload = { ok: false, error: 'orcamento_not_found' };
            return [null, msg];
        }
        if (cRes.body[0].cliente_id !== oRes.body[0].cliente_id) {
            msg.statusCode = 403;
            msg.payload = { ok: false, error: 'data_integrity_mismatch', detail: 'credito and orcamento belong to different clientes' };
            return [null, msg];
        }
        msg.authz_cliente_id = cRes.body[0].cliente_id;
    } else if (creditoId) {
        // Single-resource existence check (fail fast if the id is bogus)
        const cRes = await pgReq('GET', '/creditos_do_cliente?id=eq.' + encodeURIComponent(creditoId) + '&select=cliente_id');
        if (cRes.statusCode !== 200 || !Array.isArray(cRes.body) || cRes.body.length === 0) {
            msg.statusCode = 404;
            msg.payload = { ok: false, error: 'credito_not_found' };
            return [null, msg];
        }
        msg.authz_cliente_id = cRes.body[0].cliente_id;
    } else if (orcamentoId) {
        const oRes = await pgReq('GET', '/orcamentos?id=eq.' + encodeURIComponent(orcamentoId) + '&select=cliente_id');
        if (oRes.statusCode !== 200 || !Array.isArray(oRes.body) || oRes.body.length === 0) {
            msg.statusCode = 404;
            msg.payload = { ok: false, error: 'orcamento_not_found' };
            return [null, msg];
        }
        msg.authz_cliente_id = oRes.body[0].cliente_id;
    }
} catch (err) {
    node.warn('[authz] integrity check failed: ' + (err && err.message ? err.message : String(err)));
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'authz_check_error' };
    return [null, msg];
}

return [msg, null];

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.payload = {
    ok: true,
    module: 'orcamentos',
    env: env.get('NODE_RED_ENV') || 'unknown',
    timestamp: new Date().toISOString()
};
return msg;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const body = msg.payload || {};
const orcamentoId = body.orcamentoid;
const creditoId = body.creditoid;
const valor = Number(body.valor);

if (!orcamentoId || !UUID_RE.test(orcamentoId)) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'orcamentoid must be a valid UUID' };
    return [null, msg];
}
if (!creditoId || !UUID_RE.test(creditoId)) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'creditoid must be a valid UUID' };
    return [null, msg];
}
if (!isFinite(valor) || valor <= 0) {
    msg.statusCode = 400;
    msg.payload = { ok: false, error: 'valor must be a positive number' };
    return [null, msg];
}

msg.orcamentoId = orcamentoId;
msg.creditoId = creditoId;
msg.valor = valor;
return [msg, null];

const pgReq = global.get('pgReq');
if (typeof pgReq !== 'function') {
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'pgReq_not_available' };
    return msg;
}
const orcamentoId = msg.orcamentoId;
const creditoId = msg.creditoId;
const valor = msg.valor;
try {
    const res = await pgReq('POST', '/rpc/increment_credito_utilizacao', {
        p_credito_id: creditoId,
        p_valor: valor,
        p_orcamento_id: orcamentoId
    });
    if (res.statusCode !== 200) {
        msg.statusCode = 500;
        msg.payload = { ok: false, error: 'rpc_error', detail: res.body };
        return msg;
    }
    const r = res.body || {};
    if (!r.success) {
        msg.statusCode = 409;
        msg.payload = { ok: false, reason: r.reason || 'unknown' };
        return msg;
    }
    msg.statusCode = 200;
    msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
    msg.payload = { ok: true, new_valor_utilizado: r.new_valor_utilizado };
    return msg;
} catch (err) {
    node.error('[util-exec] ' + (err && err.message ? err.message : String(err)), msg);
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'exec_error' };
    return msg;
}

const errMsg = (msg.error && msg.error.message) || 'Unknown error';
node.warn('[registrar-utilizacao] CATCH: ' + errMsg);
msg.statusCode = msg.statusCode || 500;
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.payload = { ok: false, error: 'Internal error', flow: 'registrar-utilizacao', timestamp: new Date().toISOString() };
return msg;

