    return [null, msg];
}
msg.utilizacaoId = id;
return [msg, null];

const SUPABASE_URL = env.get('SUPABASE_URL') || '';
const SUPABASE_KEY = env.get('SUPABASE_SERVICE_ROLE_KEY') || '';
if (!SUPABASE_URL || !SUPABASE_KEY) {
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'Server misconfigured' };
    return msg;
}
const parsedSb = nodeUrl.parse(SUPABASE_URL);
const isHttps = parsedSb.protocol === 'https:';
const httpMod = isHttps ? nodeHttps : nodeHttp;
const port = parsedSb.port ? parseInt(parsedSb.port, 10) : (isHttps ? 443 : 80);

function pgReq(method, path, bodyObj, extraHeaders) {
    return new Promise((resolve, reject) => {
        const bodyStr = bodyObj ? JSON.stringify(bodyObj) : null;
        const headers = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Accept': 'application/json', 'Content-Type': 'application/json' };
        if (bodyStr) headers['Content-Length'] = Buffer.byteLength(bodyStr);
        if (extraHeaders) Object.assign(headers, extraHeaders);
        const req = httpMod.request({ method, hostname: parsedSb.hostname, port, path, headers }, (res) => {
            let data = '';
            res.on('data', c => { data += c; });
            res.on('end', () => {
                let parsedBody;
                try { parsedBody = data ? JSON.parse(data) : null; } catch (e) { parsedBody = data; }
                resolve({ statusCode: res.statusCode, body: parsedBody });
            });
        });
        req.setTimeout(30000, () => { req.destroy(new Error('Supabase request timeout')); });
        req.on('error', reject);
        if (bodyStr) req.write(bodyStr);
        req.end();
    });
}

const utilizacaoId = msg.utilizacaoId;

try {
    const utilRes = await pgReq('GET', `/rest/v1/utilizacoes_de_credito?id=eq.${encodeURIComponent(utilizacaoId)}&select=id,credito_id,valor_utilizado,utilizacao_firmada,utilizacao_cancelada`, null);
    if (utilRes.statusCode !== 200 || !Array.isArray(utilRes.body) || utilRes.body.length === 0) {
        msg.statusCode = 404;
        msg.payload = { ok: false, error: `Utilizacao '${utilizacaoId}' not found` };
        return msg;
    }
    const util = utilRes.body[0];

    if (util.utilizacao_firmada === true) {
        msg.statusCode = 200;
        msg.payload = { ok: true, id: utilizacaoId, cancelled: false, reason: 'already_firmada' };
        return msg;
    }
    if (util.utilizacao_cancelada === true) {
        msg.statusCode = 200;
        msg.payload = { ok: true, id: utilizacaoId, cancelled: false, reason: 'already_cancelled' };
        return msg;
    }

    const creditoId = util.credito_id;
    if (!creditoId) {
        msg.statusCode = 500;
        msg.payload = { ok: false, error: 'Utilizacao has no credito_id' };
        return msg;
    }
    const credRes = await pgReq('GET', `/rest/v1/creditos_do_cliente?id=eq.${encodeURIComponent(creditoId)}&select=id,valor_utilizado`, null);
    if (credRes.statusCode !== 200 || !Array.isArray(credRes.body) || credRes.body.length === 0) {
        msg.statusCode = 404;
        msg.payload = { ok: false, error: `Credito '${creditoId}' not found` };
        return msg;
    }
    const credito = credRes.body[0];

    const patchUtilRes = await pgReq('PATCH', `/rest/v1/utilizacoes_de_credito?id=eq.${encodeURIComponent(utilizacaoId)}`, {
        utilizacao_cancelada: true,
        updated_at: new Date().toISOString()
    }, null);
    if (patchUtilRes.statusCode < 200 || patchUtilRes.statusCode >= 300) {
        msg.statusCode = 500;
        msg.payload = { ok: false, error: `Failed to cancel utilizacao: HTTP ${patchUtilRes.statusCode}` };
        return msg;
    }

    const novoValorUtilizado = Math.max(0, Number(credito.valor_utilizado || 0) - Number(util.valor_utilizado || 0));
    const patchCredRes = await pgReq('PATCH', `/rest/v1/creditos_do_cliente?id=eq.${encodeURIComponent(creditoId)}`, {
        valor_utilizado: novoValorUtilizado,
        updated_at: new Date().toISOString()
    }, { 'Prefer': 'return=representation' });
    if (patchCredRes.statusCode < 200 || patchCredRes.statusCode >= 300) {
        await pgReq('PATCH', `/rest/v1/utilizacoes_de_credito?id=eq.${encodeURIComponent(utilizacaoId)}`, {
            utilizacao_cancelada: false
        }, null);
        msg.statusCode = 500;
        msg.payload = { ok: false, error: `Failed to restore credito (rolled back cancel): HTTP ${patchCredRes.statusCode}` };
        return msg;
    }
    const creditoAtualizado = Array.isArray(patchCredRes.body) && patchCredRes.body.length > 0 ? patchCredRes.body[0] : null;

    msg.statusCode = 200;
    msg.payload = {
        ok: true,
        id: utilizacaoId,
        cancelled: true,
        valorUtilizado: creditoAtualizado ? creditoAtualizado.valor_utilizado : novoValorUtilizado,
        valorDisponivel: creditoAtualizado ? creditoAtualizado.valor_disponivel : null
    };
    return msg;
} catch (err) {
    node.error('[cancelar-utilizacao] ' + (err && err.message) + (err && err.stack ? '\n' + err.stack : ''), msg);
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'Internal error' };
    return msg;
}

const errMsg = (msg.error && msg.error.message) || 'Unknown error';
node.warn('[cancelar-utilizacao] CATCH: ' + errMsg);
msg.statusCode = msg.statusCode || 500;
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.payload = { ok: false, error: 'Internal error', flow: 'cancelar-utilizacao', timestamp: new Date().toISOString() };
return msg;

