const orcamentoId = msg.orcamentoId;

try {
    const listRes = await pgReq('GET', `/rest/v1/utilizacoes_de_credito?orcamento_id=eq.${encodeURIComponent(orcamentoId)}&utilizacao_cancelada=eq.false&utilizacao_firmada=eq.false&select=id`, null);
    if (listRes.statusCode !== 200) {
        msg.statusCode = 500;
        msg.payload = { ok: false, error: `Failed to list utilizacoes: HTTP ${listRes.statusCode}` };
        if (msg._source === 'link') node.error('firmar-utilizacoes-internal: ' + msg.payload.error, msg);
        return msg;
    }
    const utilizacoes = Array.isArray(listRes.body) ? listRes.body : [];
    if (utilizacoes.length === 0) {
        msg.statusCode = 200;
        msg.payload = { ok: true, orcamentoId, count: 0 };
        return msg;
    }

    const nowIso = new Date().toISOString();
    const patchRes = await pgReq('PATCH', `/rest/v1/utilizacoes_de_credito?orcamento_id=eq.${encodeURIComponent(orcamentoId)}&utilizacao_cancelada=eq.false&utilizacao_firmada=eq.false`, {
        utilizacao_firmada: true,
        updated_at: nowIso
    }, { 'Prefer': 'return=representation' });
    if (patchRes.statusCode < 200 || patchRes.statusCode >= 300) {
        msg.statusCode = 500;
        msg.payload = { ok: false, error: `Failed to firmar utilizacoes: HTTP ${patchRes.statusCode}` };
        if (msg._source === 'link') node.error('firmar-utilizacoes-internal: ' + msg.payload.error, msg);
        return msg;
    }
    const firmadas = Array.isArray(patchRes.body) ? patchRes.body.length : utilizacoes.length;

    msg.statusCode = 200;
    msg.payload = { ok: true, orcamentoId, count: firmadas };
    return msg;
} catch (err) {
    node.error('[firmar-utilizacoes] ' + (err && err.message) + (err && err.stack ? '\n' + err.stack : ''), msg);
    msg.statusCode = 500;
    msg.payload = { ok: false, error: 'Internal error' };
    return msg;
}

const errMsg = (msg.error && msg.error.message) || 'Unknown error';
node.warn('[firmar-utilizacoes] CATCH: ' + errMsg);
msg.statusCode = msg.statusCode || 500;
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.payload = { ok: false, error: 'Internal error', flow: 'firmar-utilizacoes', timestamp: new Date().toISOString() };
if (msg._source !== 'link') {
    return [msg, null];
}
return [null, msg];

