        msg.statusCode = 400;
        msg.payload = { ok: false, error: 'quantidade_disponivel_devolucao must be > 0' };
        return msg;
    }

    // SECURITY H1: prodOsQuantidade MUST NOT exceed qtdDisponivel.
    // Before this guard, partial branch scaled valorDoCredito = (valDevolucao / qtdDisponivel) * prodOsQuantidade,
    // allowing an attacker-controlled input (prodOsQuantidade) to mint arbitrarily large credits.
    // Now rejected explicitly with 400. Only 'full' branch (prodOsQuantidade <= qtdDisponivel) is permitted.
    if (prodOsQuantidade > qtdDisponivel) {
        msg.statusCode = 400;
        msg.payload = {
            ok: false,
            error: 'prodOsQuantidade exceeds qtdDisponivel. Full devolucao only (prodOsQuantidade must be <= qtdDisponivel).',
            prodOsQuantidade,
            qtdDisponivel
        };
        return msg;
    }

    const orcRes = await pgReq('GET', `/rest/v1/orcamentos?id=eq.${encodeURIComponent(item.orcamento_id)}&select=id,cliente_id,numero_da_proposta`, null);
