        msg.payload = { ok: false, error: `Orcamento '${item.orcamento_id}' not found` };
        return msg;
    }
    const orcamento = orcRes.body[0];
    if (!orcamento.cliente_id) {
        msg.statusCode = 400;
        msg.payload = { ok: false, error: 'Orcamento has no cliente_id' };
        return msg;
    }

    let valorDoCredito;
    let branch;
    if (qtdDisponivel >= prodOsQuantidade) {
        valorDoCredito = valDevolucao;
        branch = 'full';
    } else {
        valorDoCredito = (valDevolucao / qtdDisponivel) * prodOsQuantidade;
        branch = 'partial';
    }
    valorDoCredito = Math.round(valorDoCredito * 10000) / 10000;

    const nowIso = new Date().toISOString();
    const novoCredito = {
        cliente_id: orcamento.cliente_id,
        data_de_lancamento: nowIso,
        item_de_orcamento_de_origem_id: itemOrcamentoId,
        valor_do_credito: valorDoCredito,
        valor_utilizado: 0,
        descricao_do_credito: `Devolucao de OS (prodOsId=${prodOsId})` + (orcamento.numero_da_proposta ? ` - pedido #${orcamento.numero_da_proposta}` : '')
