    node.error('[publicar-pedido] OS PTI error: ' + (err && err.message), msg);
    pub.osPtiId = null;
    msg._publicar = pub;
    return msg;
}

// Final response: publicar-pedido completed (orcamento/pedido already patched upstream).
// NOTE: transformar-em-os call removed in Phase 1.1 — OS auto-creation no longer happens here.
const pub = msg._publicar || {};

// Fire-and-forget: call /orcamentos/notificar-novo-pedido internally
// This is a placeholder flow (logs only) — safe to call best-effort
try {
    const localUrl = 'http://127.0.0.1:' + (env.get('NR_INTERNAL_PORT') || '1899') + '/orcamentos/notificar-novo-pedido';
    const body = JSON.stringify({ orcamentoid: pub.orcamentoId });
    const req = nodeHttp.request(localUrl, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Content-Length': Buffer.byteLength(body)
        },
        timeout: 5000
    }, (res) => {
        // drain response body to free socket
        res.on('data', () => {});
        res.on('end', () => {});
    });
    req.on('error', (e) => { node.warn('[publicar-pedido] notificar fire-and-forget error: ' + e.message); });
    req.on('timeout', () => { req.destroy(); });
    req.write(body);
    req.end();
} catch (e) {
    node.warn('[publicar-pedido] notificar fire-and-forget exception: ' + e.message);
}

msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.payload = {
    ok: true,
    orcamentoId: pub.orcamentoId,
    pedidoPdfId: pub.pedidoPdfId,
    osPtiId: pub.osPtiId || null,
    itensPatchedCount: pub.itensPatchedCount || 0,
    publicadoEm: new Date().toISOString()
};
return msg;

const errMsg = (msg.error && msg.error.message) || 'Unknown error';
node.warn('[publicar-pedido] CATCH: ' + errMsg);
msg.statusCode = msg.statusCode || 500;
msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.payload = { ok: false, error: 'Internal error' };
return msg;
